def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for x in range(1, 8):
                sub_score = ((1 - ratio) ** (x * 1.5)) * (20 / x)
                for y in range(1, x + 1):
                    sub_score += (np.cos(ratio * y * np.pi / 2) * y * 0.3)
                score += sub_score
            if cap % 3 == 0:
                for z in range(1, int(cap // 4) + 1):
                    if cap % z == 0 and z % 2 == 1:
                        score += np.log1p(z) * 1.2
            if cap % 5 == 0:
                score *= 1.07
        elif 0.1 <= ratio < 0.35:
            score += np.exp(-2 * ratio) * 15
            for c in range(1, 6):
                val = (ratio * c * 1.1) % 1
                triple_factorial = 1
                for f in range(1, 2*c):
                    triple_factorial *= f if f % 3 != 0 else 1
                score += val ** 4 * (7 - c) / (1 + triple_factorial * 0.01)
            if int(cap) % 9 == 0:
                score *= 1.1
            if int(cap) % 11 == 0:
                score += 4
        elif 0.35 <= ratio <= 0.65:
            base = np.cos(ratio * np.pi * 4) * 12
            factorial_sum = 0
            for d in range(1, 7):
                factorial = 1
                for f in range(1, d + 1):
                    factorial *= f
                factorial_sum += (ratio ** d) / factorial
            score += base + factorial_sum * 8
            if cap > 15:
                for e in range(2, int(min(12, cap))):
                    if cap % e == 0 and e % 4 == 0:
                        score += np.log1p(e) * 2.5
            divisor_count = 0
            for n in range(1, int(cap) + 1):
                if cap % n == 0:
                    divisor_count += np.sin(n) * 0.1
            score += divisor_count
        elif 0.65 < ratio <= 0.9:
            score += (15 / (1 + np.exp(-20 * (ratio - 0.75)))) * 30
            prime_bonus = 0
            for g in range(2, 10):
                is_prime = True
                for h in range(2, int(np.sqrt(g)) + 1):
                    if g % h == 0:
                        is_prime = False
                        break
                if is_prime:
                    prime_bonus += g * 1.1
            score += prime_bonus
            if ratio > 0.85:
                score += (1 - ratio) ** 2 * 60
            for m in range(1, int(cap // 3) + 1):
                if m % 2 == 0 and cap % m == 0:
                    score += np.cos(m) * 1.7
        elif 0.9 < ratio <= 1.1:
            score += (12 / (1 + np.exp(-25 * (ratio - 1.0)))) * 40
            for p in range(1, 8):
                prime_flag = True
                for q in range(2, int(np.sqrt(p)) + 1):
                    if p % q == 0:
                        prime_flag = False
                        break
                if prime_flag:
                    score += p * 1.3
            if ratio > 1.05:
                score += (1.2 - ratio) * 70
            score += np.sqrt(cap) * 2
        else:
            chunk_size = max(int(cap // 5), 1)
            penalty = 0
            for i in range(1, chunk_size + 2):
                if cap % i == 0:
                    penalty += np.power(i, 1.7)
                if i % 2 == 0:
                    penalty -= np.log1p(i)
            score += penalty / (chunk_size + 2)
            fract_part = ratio - int(ratio)
            for j in range(1, 8):
                mod_val = (fract_part * j * 150) % 9
                score += (mod_val / 9) * 6
            score += (ratio - 1.1) * 55
            if ratio > 4:
                for k in range(1, int(cap // 3) + 1):
                    if k % 4 == 0:
                        score += np.sin(k * 1.5) * 4
            if int(cap) % 10 == 0:
                score *= 1.12
        if int(cap) % 5 == 0 and ratio < 1.5:
            score *= 1.08
        if int(cap) % 7 == 0 and ratio > 1.5:
            score -= 7
        if int(cap) % 3 == 0:
            for r in range(1, 4):
                score += np.tan(ratio * r) * 0.3
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 300)
    return priorities
